INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a2c10900-0000-4000-8000-000000000000','a2c00000-0000-4000-8000-000000000000','確認テスト ─ 事業計画の策定','quiz',NULL,NULL,NULL,3,2),
  ('a2c20900-0000-4000-8000-000000000000','a2c00000-0000-4000-8000-000000000000','確認テスト ─ 予算策定と予実管理','quiz',NULL,NULL,NULL,3,4),
  ('a2c30900-0000-4000-8000-000000000000','a2c00000-0000-4000-8000-000000000000','確認テスト ─ プロジェクトマネジメント','quiz',NULL,NULL,NULL,3,6),
  ('a2c40900-0000-4000-8000-000000000000','a2c00000-0000-4000-8000-000000000000','確認テスト ─ 業績会議の設計','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a2c10900-0000-4000-8000-000000000000','本文が定める「事業計画」の本質は、次のどれか。','ありたい姿への道筋を、前提と数字で、他者と共有できる形にすること','市場を調べ尽くし、数字を細部まで詰めて製本すること','3年後の売上と利益を、正確に予測して当てること','到達したい数字と明るい言葉を、前向きに並べること','A',0),
('a2c10900-0000-4000-8000-000000000000','本文で言う「動く計画」の価値は、どこにあるとされるか。','精緻な予測を積み上げ、細部まで正確に当たること','ズレたときに、どの前提が外れたかを特定し、立て直せること','完成度が高く、立派に製本されて棚に残ること','数字の欄が、隅々まできれいに埋まっていること','B',1),
('a2c10900-0000-4000-8000-000000000000','五つのステップのうち「③戦略の選択」で、本文が戦略の本質だとするのはどれか。','やることを、できるだけ多く決めること','前年比を掛けて、数字をするすると並べること','何で勝つかを決め、そのために何を捨てるかを決めること','現状分析で、自社の強みを大きく盛って書くこと','C',2),
('a2c20900-0000-4000-8000-000000000000','本文が示す「予実管理」の本質は、次のどれか。','計画に届いたかを採点し、届かなければ誰が悪いかを決める道具','去年の数字に一律で上乗せし、予算を効率よく組む道具','数字を裁く道具ではなく、現場と打ち手を対話する道具','未達のチームを呼び、なぜ届かないのかを詰める道具','C',0),
('a2c20900-0000-4000-8000-000000000000','本文で、売上のズレを「切り分ける」三つの観点は、次のどれか。','数量・単価・時期','計画比・前年比・予兆','成果物・期日・品質','積み上げ・トップダウン・すり合わせ','A',1),
('a2c20900-0000-4000-8000-000000000000','予算を「前年踏襲で、根拠なく数字を置く」失敗に対する、本文の修正はどれか。','経営の数字を、そのまま各チームに割り振る','数字の裏に、一行の根拠(前提)を置く','期末に、売上を今期へ前倒しして帳尻を合わせる','未達のチームに、なぜできないのかを問い続ける','B',2),
('a2c30900-0000-4000-8000-000000000000','本文が定める「プロジェクトマネジメント」の本質は、次のどれか。','自分が全案件に深く手を入れ、気合で全部を成立させること','起こりうる失敗を、すべて潰してから動き出すこと','限られた資源で、何を・いつまでに・どの品質で成立させるかを段取りする技術','一番うるさい案件に飛び込んで、その火を消して回ること','C',0),
('a2c30900-0000-4000-8000-000000000000','本文が、資源を配分するときに勧める見積もり方はどれか。','自分の資源を八割で見積もり、二割をバッファとして空ける','すべての案件を最高品質で仕上げる前提で組む','一〇〇%詰め切って、余白なく計画を組む','全案件に、同じだけ均等に力を配る','A',1),
('a2c30900-0000-4000-8000-000000000000','リスクを先回りして潰す「事前の検死」で、本文が勧める視点はどれか。','成功する道すじを、うまくいく理由から積み上げる','起こりうる失敗を、確率にかかわらず全部潰し切る','失敗した未来から逆算し、何が起きたのかを書き出す','火が出てから駆けつけ、その都度すばやく消す','C',2),
('a2c40900-0000-4000-8000-000000000000','本文が定める「業績会議」の本質は、次のどれか。','各チームが数字を順番に読み上げ、状況を共有する場','数字を報告する場ではなく、数字を起点に次の打ち手を決める場','未達のチームに、なぜできなかったのかを問い詰める場','先月どうだったかを、計画比と前年比で答え合わせする場','B',0),
('a2c40900-0000-4000-8000-000000000000','本文で、数字を読む「三つの角度」として挙げられているのはどれか。','成果物・期日・品質','数量・単価・時期','計画比・前年比・予兆','事前準備・深掘り・上申','C',1),
('a2c40900-0000-4000-8000-000000000000','「決めずに、次回へ持ち越す」失敗に対する、本文の修正はどれか。','やり直せる打ち手なら、その場で80点で、担当と期限まで決め切る','完璧な合意ができるまで、来月にもう一度検討する','打ち手は、経験のある自分が全部その場で決めてしまう','来月は気合いで巻き返そう、と精神論で締める','A',2);
